css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #030a03; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 76px; border-bottom: 1px solid rgba(34,197,94,0.15); }
.logo { font-size: 22px; font-weight: 900; letter-spacing: 1px; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.join { padding: 12px 24px; border-radius: 10px; border: none; background: #22c55e; color: #030a03; font-weight: 800; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 76px); }
.hero-tag { display: inline-block; color: #22c55e; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 24px; }
h1 { font-size: 80px; font-weight: 900; line-height: 0.95; letter-spacing: -3px; margin-bottom: 24px; } h1 span { color: #22c55e; }
.hero-content p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 36px; max-width: 440px; }
.hero-actions { display: flex; gap: 14px; margin-bottom: 48px; }
.btn-start { padding: 16px 32px; border-radius: 12px; border: none; background: #22c55e; color: #030a03; font-weight: 800; font-size: 16px; cursor: pointer; }
.btn-watch { padding: 16px 28px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.hero-numbers { display: flex; gap: 36px; } .num-item strong { display: block; font-size: 32px; font-weight: 900; color: #22c55e; } .num-item span { color: #4b5563; font-size: 13px; }
.progress-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(34,197,94,0.2); border-radius: 20px; padding: 24px; }
.pc-header { font-size: 16px; font-weight: 700; margin-bottom: 20px; color: #e2e8f0; }
.workout-list { display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px; }
.w-item { display: flex; align-items: center; gap: 12px; font-size: 14px; padding: 10px; border-radius: 8px; }
.w-item.done { color: #6b7280; background: rgba(255,255,255,0.03); } .w-item.active { background: rgba(34,197,94,0.1); color: white; }
.check { width: 20px; text-align: center; } .check.active { color: #22c55e; } .check.empty { color: #374151; }
.w-cal { margin-left: auto; color: #22c55e; font-size: 12px; font-weight: 700; }
.pb-label { display: flex; justify-content: space-between; font-size: 13px; color: #6b7280; margin-bottom: 8px; }
.pb { height: 6px; background: rgba(255,255,255,0.08); border-radius: 3px; margin-bottom: 16px; } .pb-fill { height: 100%; border-radius: 3px; background: linear-gradient(90deg, #22c55e, #86efac); }
.calorie-count { text-align: center; font-size: 14px; font-weight: 700; color: #22c55e; }
.programs { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.06); } .programs h2 { font-size: 42px; font-weight: 800; margin-bottom: 40px; }
.prog-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
.prog-card { padding: 28px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); }
.prog-icon { font-size: 36px; margin-bottom: 14px; } .prog-card h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; } .prog-card p { color: #6b7280; font-size: 13px; line-height: 1.6; margin-bottom: 16px; }
.prog-level { padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 700; } .beginner { background: rgba(34,197,94,0.15); color: #22c55e; } .intermediate { background: rgba(234,179,8,0.15); color: #eab308; } .advanced { background: rgba(239,68,68,0.15); color: #ef4444; }
